using SeedApi;

var client = new SeedApiClient();
await client._.CreateAsync(
    new CreateRequest
    {
        Decimal = 1.1,
        Even = 1,
        Name = "name",
        Shape = Shape.Square,
    }
);

using SeedApi;

var client = new SeedApiClient();
await client._.GetAsync(
    new GetRequest
    {
        Decimal = 1.1,
        Even = 1,
        Name = "name",
    }
);
